import { moduleMetadata } from '@storybook/angular';
import { PfSelectComponent } from './select.component';
const meta = {
    title: 'Composants graphiques/Select',
    component: PfSelectComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Liste déroulante simple basée sur `<select>` natif. Conçu pour l'a11y native, l'UX mobile (picker système) et un bundle minimal.",
            },
        },
    },
    decorators: [
        moduleMetadata({ imports: [PfSelectComponent] }),
        (storyFn) => {
            const story = storyFn();
            return { ...story, template: `<div style="width: 320px;">${story.template}</div>` };
        },
    ],
    argTypes: {
        size: { control: 'inline-radio', options: ['sm', 'md', 'lg'] },
        required: { control: 'boolean' },
        disabled: { control: 'boolean' },
    },
    args: {
        label: 'Civilité',
        placeholder: 'Sélectionnez votre civilité',
        options: [
            { value: 'mme', label: 'Madame' },
            { value: 'm', label: 'Monsieur' },
            { value: 'autre', label: 'Autre' },
        ],
        size: 'md',
    },
    render: (args) => ({
        props: args,
        template: `<pf-select
      [label]="label"
      [hint]="hint"
      [error]="error"
      [placeholder]="placeholder"
      [size]="size"
      [options]="options"
      [required]="required"
      [disabled]="disabled"
      [value]="value"
      (valueChange)="value = $event"
    ></pf-select>`,
    }),
};
export default meta;
export const Default = {};
export const WithHint = {
    args: { hint: "Telle que figurant sur votre pièce d'identité." },
};
export const Required = { args: { required: true } };
export const WithError = {
    args: { error: 'Ce champ est obligatoire.', required: true },
};
export const Disabled = {
    args: { disabled: true, value: 'mme' },
};
export const WithDisabledOption = {
    args: {
        label: 'Mode de livraison',
        placeholder: 'Choisir un mode',
        options: [
            { value: 'standard', label: 'Standard (3-5 jours)' },
            { value: 'express', label: 'Express (24h)', disabled: true },
            { value: 'pickup', label: 'Retrait en agence' },
        ],
    },
};
export const Sizes = {
    render: () => ({
        template: `
      <div style="display: flex; flex-direction: column; gap: 12px;">
        <pf-select
          label="Petit"
          size="sm"
          [options]="[{ value: 'a', label: 'Option A' }, { value: 'b', label: 'Option B' }]"
        ></pf-select>
        <pf-select
          label="Moyen"
          size="md"
          [options]="[{ value: 'a', label: 'Option A' }, { value: 'b', label: 'Option B' }]"
        ></pf-select>
        <pf-select
          label="Grand"
          size="lg"
          [options]="[{ value: 'a', label: 'Option A' }, { value: 'b', label: 'Option B' }]"
        ></pf-select>
      </div>
    `,
    }),
};
